import{_ as i,o as a,c as e,ae as o}from"./chunks/framework.RRduUuAx.js";const P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/network/chapter-8.md","filePath":"szu/network/chapter-8.md"}'),t={name:"szu/network/chapter-8.md"};function r(u,l,h,n,s,c){return a(),e("div",null,[...l[0]||(l[0]=[o('<h2 id="一-、网络安全概述" tabindex="-1">(一)、网络安全概述 <a class="header-anchor" href="#一-、网络安全概述" aria-label="Permalink to &quot;(一)、网络安全概述&quot;">​</a></h2><ol><li>基本概念 <ul><li>网络安全基本属性：机密性、消息完整性、可访问与可用性、身份认证</li></ul></li><li>网络安全威胁 <ul><li>从报文传输方便，主要包括窃听、插入、假冒、劫持等安全威胁。</li><li>网络攻击还包括拒绝服务 Dos 以及分布式拒绝服务 DDos 等。拒绝服务是指阻止服务器为其他用户提供服务。</li><li>映射、“嗅探”、IP 欺骗</li></ul></li></ol><h2 id="二-、数据加密" tabindex="-1">(二)、数据加密 <a class="header-anchor" href="#二-、数据加密" aria-label="Permalink to &quot;(二)、数据加密&quot;">​</a></h2><ol><li>传统加密方式 <ul><li>1.替代密码</li><li>2.换位密码。又称为置换密码。</li></ul></li><li>对称秘钥加密 <ul><li>1.DES 加密算法</li><li>2.三重 DES</li><li>3.AES 加密算法</li><li>4.IDEA 加密算法</li></ul></li><li>非对称/公开秘钥加密</li></ol><h2 id="三-、消息完整性与数字签名" tabindex="-1">(三)、消息完整性与数字签名 <a class="header-anchor" href="#三-、消息完整性与数字签名" aria-label="Permalink to &quot;(三)、消息完整性与数字签名&quot;">​</a></h2><ol><li>消息完整性检测方法 <ul><li>MD5</li><li>SHA-1</li></ul></li><li>报文认证 <ul><li>简单报文验证</li><li>报文认证码 MAC</li></ul></li><li>数字签名 <ul><li>简单数字签名</li><li>签名报文摘要</li></ul></li></ol><h2 id="四-、身份认证" tabindex="-1">(四)、身份认证 <a class="header-anchor" href="#四-、身份认证" aria-label="Permalink to &quot;(四)、身份认证&quot;">​</a></h2><ul><li>身份鉴别应当在通信双发的报文和数据交换的基础上，作为某鉴别协议的一部分独立完成。</li><li>鉴别协议通常在两个通信实体运行其他协议之前运行。</li><li>鉴别协议首先建立相互信任的各方的标识，仅当鉴别完成之后，各方才继续之后的工作。</li></ul><h2 id="五-、秘钥分发中心与证书认证" tabindex="-1">(五)、秘钥分发中心与证书认证 <a class="header-anchor" href="#五-、秘钥分发中心与证书认证" aria-label="Permalink to &quot;(五)、秘钥分发中心与证书认证&quot;">​</a></h2><ol><li>秘钥分发中心</li><li>证书认证机构</li></ol><h2 id="六-、防火墙与入侵检测系统" tabindex="-1">(六)、防火墙与入侵检测系统 <a class="header-anchor" href="#六-、防火墙与入侵检测系统" aria-label="Permalink to &quot;(六)、防火墙与入侵检测系统&quot;">​</a></h2><ol><li>防火墙基本概念 <ul><li>防火墙是能够隔离组织内部网络与公共互联网，允许某些分组通过，而阻止其他分组进入或离开内部网络的软件、硬件或者软件硬件结合的一种设施。</li></ul></li><li>防火墙分类 <ul><li>无状态分组过滤器</li><li>有状态分组过滤器</li><li>应用网关</li></ul></li><li>入侵检测系统 IDS <ul><li>防火墙在决定让哪个分组经过防火墙时，分组过滤器检查 IP、TCP、UDP、ICMP 首部字段。为了检测多种攻击类型，则需要执行深度分组检查，查看首部字段之外的部分，深入查看分组携带的实际数据。</li></ul></li></ol><h2 id="七-、网络安全协议" tabindex="-1">(七)、网络安全协议 <a class="header-anchor" href="#七-、网络安全协议" aria-label="Permalink to &quot;(七)、网络安全协议&quot;">​</a></h2><ol><li>安全电子邮件 <ul><li>安全电子邮件基本原理</li><li>安全电子邮件标准</li></ul></li><li>安全套接字层 SSL <ul><li>SSL 简介 <ul><li>介于应用层和传输层之间，类似于会话层，可作为基础协议栈的一部分，也可以直接嵌入到流浪器中使用。</li></ul></li><li>SSL 协议栈</li><li>SSL 的握手过程</li></ul></li><li>虚拟专用网 VPN 和 IP 安全协议 IPSec <ul><li>VPN 简介 <ul><li>专用网络（PN）。是基于专属的网络设备、链路或协议等建立的专门服务于特定组织机构的网络，例如，民航网络、军事网络等，是不与公共网络互连，只在组织内部使用的网络。</li><li>虚拟专用网络 VPN 通过建立在公共网络上的安全通道，实现对特定组织机构的专用网络。</li><li>VPN 涉及的技术有很多，关键技术有隧道技术、数据加密、身份认证、秘钥管理、访问控制和网络管理等，其中相对核心的是隧道技术。</li></ul></li><li>IPSec 体系简介</li><li>安全管理 SA</li><li>AH 协议和 ESP</li><li>IPsec 密钥交换 IKE</li></ul></li></ol>',14)])])}const S=i(t,[["render",r]]);export{P as __pageData,S as default};
